@router.post("/{task_id}/add_row", response_model=None)
async def add_row(task_id: str, request: Request):
    """Append one empty proposal row to the draft form.

    Two transports, same end state:

    - With JS, htmx posts here with ``HX-Request: true``. We respond
      with the rendered ``_proposal_row.html`` fragment for the new
      row only; htmx swaps it as ``beforeend`` of ``#proposal-rows``
      so the user's existing input is untouched. Redirect/error
      branches send ``HX-Redirect`` on a 204 so htmx does a full
      client-side navigation rather than swapping a redirected page
      into the rows container.
    - Without JS, the same button submits the form normally and we
      re-render the whole ``planner_claim.html`` with the
      collected state plus one more empty row, or 303 to the
      sign-in / planner list on auth/claim failures.
    """
    session = get_session(request)
    if session is None:
        return htmx_aware_redirect(request, "/signin")
    form = await request.form()
    if not csrf_ok(session, form.get("csrf_token")):  # type: ignore[arg-type]
        return _csrf_failure_response(request)
    if _CLAIMS.get(_claim_key(session.csrf, task_id)) is None:
        return htmx_aware_redirect(
            request, "/planner/?banner=claim+missing+from+session"
        )

    if is_htmx_request(request):
        # The htmx-enhanced path: figure out where the new row goes
        # by counting existing rows in the form, then render only
        # the partial. The user's existing rows are already on the
        # page; htmx appends ours to ``#proposal-rows``.
        existing = max(
            len(form.getlist("slug")),
            len(form.getlist("priority")),
            len(form.getlist("parent_commits")),
            len(form.getlist("rationale")),
        )
        return request.app.state.templates.TemplateResponse(
            request,
            "_proposal_row.html",
            {"i": existing, "row_state": _empty_row(), "row_errs": {}},
        )

    config = request.app.state.experiment_config
    slugs = [str(v) for v in form.getlist("slug")]
    priorities = [str(v) for v in form.getlist("priority")]
    parents = [str(v) for v in form.getlist("parent_commits")]
    rationales = [str(v) for v in form.getlist("rationale")]
    state = _form_state_from_inputs(slugs, priorities, parents, rationales)
    state.append(_empty_row())
    return request.app.state.templates.TemplateResponse(
        request,
        "planner_claim.html",
        {
            "session": session,
            "task_id": task_id,
            "objective": config.objective,
            "metrics_schema": config.metrics_schema.root,
            "errors": None,
            "form_state": state,
            "row_indices": list(range(len(state))),
        },
    )


@router.post("/{task_id}/submit", response_model=None)
async def submit_plan(task_id: str, request: Request) -> HTMLResponse | RedirectResponse:
    session = get_session(request)
    if session is None:
        return RedirectResponse(url="/signin", status_code=303)
    form = await request.form()
    if not csrf_ok(session, form.get("csrf_token")):  # type: ignore[arg-type]
        return _csrf_failure_response(request)
    status = form.get("status")
    if status not in ("success", "error"):
        return _bad_request("invalid submit status")

    token = _CLAIMS.get(_claim_key(session.csrf, task_id))
    if token is None:
        return RedirectResponse(
            url="/planner/?banner=claim+missing+from+session",
            status_code=303,
        )

    store = request.app.state.store
    config = request.app.state.experiment_config

    if status == "error":
        try:
            store.submit(task_id, token, PlanSubmission(status="error"))
        except DispatchError as exc:
            return _render_error(request, _wire_error_banner(exc))
        _CLAIMS.pop(_claim_key(session.csrf, task_id), None)
        return _render_submitted(request, task_id, status="error", proposal_ids=())

    slugs = [str(v) for v in form.getlist("slug")]
    priorities = [str(v) for v in form.getlist("priority")]
    parents = [str(v) for v in form.getlist("parent_commits")]
    rationales = [str(v) for v in form.getlist("rationale")]
    drafts, errors = parse_proposal_rows(slugs, priorities, parents, rationales)
    if errors:
        return request.app.state.templates.TemplateResponse(
            request,
            "planner_claim.html",
            {
                "session": session,
                "task_id": task_id,
                "objective": config.objective,
                "metrics_schema": config.metrics_schema.root,
                "errors": errors,
                "form_state": _form_state_from_inputs(slugs, priorities, parents, rationales),
                "row_indices": list(range(max(1, len(slugs) or 1))),
            },
            status_code=400,
        )

    proposal_ids: list[str] = []

"""Admin-module routes — observability views + operator actions.

Implements the chunk 9e plan: read-only views over tasks / trials /
events, an operator ``reclaim`` action on tasks, and a ``work/*`` ref
GC page when ``--repo-path`` is configured.

Auth-first POST discipline: every handler — GET and POST — runs
``get_session(request)`` first; an absent session redirects to
``/signin``. CSRF runs after the auth check on mutating routes.
This matches the planner / implementer / evaluator pattern.
"""

from __future__ import annotations

import re
from collections.abc import Callable
from datetime import datetime
from typing import Any

from eden_contracts import Event, Task, Trial
from eden_storage.errors import IllegalTransition
from eden_storage.errors import NotFound as StorageNotFound
from fastapi import APIRouter, Form, Request
from fastapi.responses import HTMLResponse, RedirectResponse

from ._helpers import csrf_ok, get_session, read_trial_artifact

router = APIRouter(prefix="/admin")


_DEFAULT_EVENTS_LIMIT = 200
_MAX_EVENTS_LIMIT = 1000
_TRIAL_DETAIL_EVENT_CAP = 50

_KIND_VALUES = ("plan", "implement", "evaluate")
_STATE_VALUES = ("pending", "claimed", "submitted", "completed", "failed")
_TRIAL_STATUS_VALUES = ("starting", "success", "error", "eval_error")

# Closed allowlist: ?error=… and ?reclaimed=… banner copy. Keys
# match the querystring values; values are (level, message).
_RECLAIM_OUTCOMES: dict[str, tuple[str, str]] = {
    "ok": ("ok", "task reclaimed"),
    "illegal-transition": (
        "error",
        "this task cannot be reclaimed (terminal or not claimed)",
    ),
    "transport": (
        "error",
        "transport failure; refresh and try again if the task did not move to pending",
    ),
}

_REF_DELETE_OUTCOMES: dict[str, tuple[str, str]] = {
    "ok": ("ok", "ref deleted"),
    "invalid-ref-name": ("error", "ref name is not a work-branch ref"),
    "not-eligible": ("error", "ref is not eligible for deletion"),
    "not-found": ("error", "ref no longer exists"),
    "ref-changed": (
        "error",
        "ref changed since you loaded the page; refresh and re-confirm",
    ),
    "transport": ("error", "git operation failed; check server logs"),
}

# refs/heads/work/<segment>(/<segment>)*
# Each segment matches [A-Za-z0-9_.-]+; we forbid empty segments and
# anything that could escape the work/ namespace.
_WORK_REF_RE = re.compile(r"^refs/heads/work/[A-Za-z0-9_.\-]+(?:/[A-Za-z0-9_.\-]+)*$")


# A sentinel returned by ``_coerce_filter`` to mean "the operator
# typed a filter value that isn't in the allowed set". The route
# layer renders an empty rowset for this case (plan §A.3) — distinct
# from ``None`` which means "no filter applied".
_INVALID_FILTER = "__invalid__"


def _coerce_filter(raw: str | None, allowed: tuple[str, ...]) -> str | None:
    """Map ``raw`` to a value in ``allowed``, ``None`` (no filter), or ``_INVALID_FILTER``."""
    if raw is None or raw == "*" or raw == "":
        return None
    if raw in allowed:
        return raw
    return _INVALID_FILTER


def _claim_age_seconds(task: Task, now: datetime) -> float | None:
    if task.claim is None:
        return None
    claimed_at = _parse_dt(task.claim.claimed_at)
    if claimed_at is None:
        return None
    return (now - claimed_at).total_seconds()


def _claim_expired(task: Task, now: datetime) -> bool:
    if task.claim is None or task.claim.expires_at is None:
        return False
    expires_at = _parse_dt(task.claim.expires_at)
    if expires_at is None:
        return False
    return expires_at < now


def _parse_dt(raw: str | datetime | None) -> datetime | None:
    if raw is None:
        return None
    if isinstance(raw, datetime):
        return raw
    try:
        return datetime.fromisoformat(raw)
    except ValueError:
        return None


def _trial_terminal_handled(trial: Trial) -> bool:
    """Return True iff the trial has reached a terminal-and-handled status."""
    if trial.status in {"error", "eval_error"}:
        return True
    return trial.status == "success" and trial.trial_commit_sha is not None


def _now_dt(request: Request) -> datetime:
    fn: Callable[[], datetime] = request.app.state.now
    return fn()


